import _m0 from "protobufjs/minimal";
import { Coin } from "../../../cosmos/base/v1beta1/coin";
import { RollappPacket_Type, rollappPacket_TypeFromJSON, rollappPacket_TypeToJSON } from "../common/rollapp_packet";
import { Status, statusFromJSON, statusToJSON } from "../common/status";

export const protobufPackage = "dymensionxyz.dymension.eibc";

export interface DemandOrder {
  /**
   * id is a hash of the form generated by GetRollappPacketKey,
   * e.g
   * status/rollappid/packetProofHeight/packetDestinationChannel-PacketSequence
   * which guarantees uniqueness
   */
  id: string;
  /**
   * tracking_packet_key is the key of the packet that is being tracked.
   * This key can change depends on the packet status.
   */
  trackingPacketKey: string;
  /**
   * price is the amount that the fulfiller sends to original eibc transfer
   * recipient
   */
  price: Coin[];
  /**
   * fee is the effective profit made by the fulfiller because they pay price
   * and receive fee + price
   */
  fee: Coin[];
  recipient: string;
  trackingPacketStatus: Status;
  rollappId: string;
  type: RollappPacket_Type;
  /**
   * fulfiller_address is the bech32-encoded address of the account which
   * fulfilled the order.
   */
  fulfillerAddress: string;
}

function createBaseDemandOrder(): DemandOrder {
  return {
    id: "",
    trackingPacketKey: "",
    price: [],
    fee: [],
    recipient: "",
    trackingPacketStatus: 0,
    rollappId: "",
    type: 0,
    fulfillerAddress: "",
  };
}

